mapper.select:
SELECT id, version_name AS versionName, node_code AS nodeCode, title, status, description, org_level AS orgLevel, dept_name AS deptName, office_name AS officeName, delivery_info AS deliveryInfo, sql5_text AS sql5Text, scene_name AS sceneName, node_type_category AS nodeTypeCategory, node_type_name AS nodeTypeName, due_date AS dueDate, planned_start AS plannedStart, planned_end AS plannedEnd, data_org_level AS dataOrgLevel, channel, created_by AS createBy, created_at AS createTime, updated_by AS updateBy, updated_at AS updateTime, delete_flag AS deleteFlag, t_day FROM bpm_node_instance_format WHERE 1 = 1
AND t_day = #{tDay}
AND version_name = #{versionName}
AND sql5_text = #{procDateType.code}
AND org_level LIKE #{orgLevelLike}
AND node_code LIKE CONCAT(#{nodeCodePrefix}, '%')
AND delete_flag = '0'
